import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            tf = fw.get('framework', '')
            for pkg in fw.get('topLevelPackages', []):
                key = (pkg['id'], tf)
                pkgs[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion', '?'))
        result[name] = pkgs
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key)
        av = ap.get(key)
        pkg_id, tf = key
        if bv != av:
            changes.append((proj, pkg_id, tf, bv or 'N/A', av or 'N/A'))
        else:
            unchanged.append((proj, pkg_id, tf, bv))

if changes:
    print('CHANGES:')
    for proj, pkg, tf, bv, av in changes:
        print(f'  {proj} | {pkg} ({tf}): {bv} -> {av}')
else:
    print('NO CHANGES - all packages resolve identically to baseline')
print(f'\\nUnchanged: {len(unchanged)} package/framework combinations')
"

